private func reloadVisibleThumbnails(forceReloadVisible: Bool = false) {
    let visibleItems = collectionView.indexPathsForVisibleItems()
    let indices = visibleItems.map(\.item)   // ← 第一次遍歷，建立 [Int] 陣列
    let center = indices.isEmpty ? 0 : (indices.min()! + indices.max()!) / 2   // ← 又遍歷兩次（min + max）
    // ...
    for indexPath in visibleItems {   // ← 第三次遍歷
        if let cell = collectionView.item(at: indexPath) as? QuickGridCell {
            loadThumbnail(for: indexPath.item, cell: cell, visibleCenter: center, forceReload: forceReloadVisible)
        }
    }
}
```
